Consider the C function given below.

int f(int j)
{
    static int i = 50;
    int k;
    if (i == j)
    {
        printf("something");
        k = f(i);
        return 0;
    }
    else return 0;
}

Which one of the following is TRUE?

A. The function returns 0 for all values of j.
B. The function prints the string something for all values of j.
C. The function returns 0 when j = 50.
D. The function will exhaust the runtime stack or run into an infinite loop when j = 50.

The output of the following C program is __________.

void f1(int a, int b)
{
    int c;
    c = a; a = b; b = c;
}

void f2(int *a, int *b)
{
    int c;
    c = *a; *a = *b; *b = c;
}

int main()
{
    int a = 4, b = 5, c = 6;
    f1(a, b);
    f2(&b, &c);
    printf("%d", c - a - b);
    return 0;
}

A. -5
B. -4
C. 5
D. 3

Consider the following C program:

#include <stdio.h>
int f1(void);
int f2(void);
int f3(void);
int x = 10;

int main()
{
    int x = 1;
    x += f1() + f2() + f3() + f2();
    printf("%d", x);
    return 0;
}

int f1(void) { return (x + 1); }
int f2(void) { return (x + 1); }
int f3(void) { int x = 1; return (x + 1); }

The output of the program is __________.

A. 9
B. 18
C. 36
D. 46
